import{_ as a,o as e,c as n,ag as t}from"./chunks/framework.BmJvwvJl.js";const u=JSON.parse('{"title":"项目结构","description":"","frontmatter":{},"headers":[],"relativePath":"reference/repo-structure.md","filePath":"reference/repo-structure.md"}'),o={name:"reference/repo-structure.md"};function p(d,s,r,l,i,c){return e(),n("div",null,[...s[0]||(s[0]=[t(`<h1 id="项目结构" tabindex="-1">项目结构 <a class="header-anchor" href="#项目结构" aria-label="Permalink to &quot;项目结构&quot;">​</a></h1><p>XHSOps 将仓库划分为两层空间，分别承担不同职责。</p><h2 id="两层空间" tabindex="-1">两层空间 <a class="header-anchor" href="#两层空间" aria-label="Permalink to &quot;两层空间&quot;">​</a></h2><table tabindex="0"><thead><tr><th>空间</th><th>位置</th><th>用途</th></tr></thead><tbody><tr><td>系统工作区</td><td><code>.xhsops/</code></td><td>内部资产、workflow 产物、规范定义</td></tr><tr><td>人用交付区</td><td><code>publish/</code></td><td>直接给读者看的终稿成品</td></tr></tbody></table><p><strong>为什么分开？</strong></p><ul><li><code>.xhsops/</code> 是 AI 和系统内部用的，包含大量中间产物和协议文件</li><li><code>publish/</code> 是给人直接消费的，只有终稿和配套素材</li><li>分开后，不会把脏乱的工作区暴露给读者</li></ul><hr><h2 id="完整目录结构" tabindex="-1">完整目录结构 <a class="header-anchor" href="#完整目录结构" aria-label="Permalink to &quot;完整目录结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>项目根目录/</span></span>
<span class="line"><span>├── .xhsops/                    # 系统工作区</span></span>
<span class="line"><span>│   ├── brand/                  # 品牌语境</span></span>
<span class="line"><span>│   │   ├── profile.md          # 你是谁</span></span>
<span class="line"><span>│   │   ├── audience.md         # 读者是谁</span></span>
<span class="line"><span>│   │   ├── offer.md             # 提供什么价值</span></span>
<span class="line"><span>│   │   ├── tone.md              # 语气风格</span></span>
<span class="line"><span>│   │   └── taboo.md             # 不写什么</span></span>
<span class="line"><span>│   ├── strategy/               # 内容策略</span></span>
<span class="line"><span>│   │   ├── content-pillars.md   # 内容支柱</span></span>
<span class="line"><span>│   │   └── topic-frameworks.md  # 选题框架</span></span>
<span class="line"><span>│   ├── specs/                  # 规则定义</span></span>
<span class="line"><span>│   ├── commands/               # workflow 定义</span></span>
<span class="line"><span>│   ├── prompts/                # agent 协议</span></span>
<span class="line"><span>│   ├── quick/                  # quick runs</span></span>
<span class="line"><span>│   ├── trends/                 # trend runs</span></span>
<span class="line"><span>│   ├── campaigns/              # campaigns</span></span>
<span class="line"><span>│   └── knowledge/              # 复盘经验</span></span>
<span class="line"><span>├── publish/                    # 交付区（按日期）</span></span>
<span class="line"><span>│   └── 2026-03-13/</span></span>
<span class="line"><span>│       └── quick-xxx-标题/</span></span>
<span class="line"><span>│           ├── note.md</span></span>
<span class="line"><span>│           ├── cover-brief.md</span></span>
<span class="line"><span>│           ├── assets.md</span></span>
<span class="line"><span>│           └── publish-guide.md</span></span>
<span class="line"><span>└── ...</span></span></code></pre></div><hr><h2 id="各目录详解" tabindex="-1">各目录详解 <a class="header-anchor" href="#各目录详解" aria-label="Permalink to &quot;各目录详解&quot;">​</a></h2><h3 id="xhsops-brand-—-品牌语境" tabindex="-1">.xhsops/brand/ — 品牌语境 <a class="header-anchor" href="#xhsops-brand-—-品牌语境" aria-label="Permalink to &quot;.xhsops/brand/ — 品牌语境&quot;">​</a></h3><p>定义「你是谁」系列，回答：</p><ul><li><code>profile.md</code> — 账号身份定位</li><li><code>audience.md</code> — 目标读者画像</li><li><code>offer.md</code> — 核心价值主张</li><li><code>tone.md</code> — 文风语气</li><li><code>taboo.md</code> — 绝对不写的内容</li></ul><h3 id="xhsops-strategy-—-内容策略" tabindex="-1">.xhsops/strategy/ — 内容策略 <a class="header-anchor" href="#xhsops-strategy-—-内容策略" aria-label="Permalink to &quot;.xhsops/strategy/ — 内容策略&quot;">​</a></h3><ul><li><code>content-pillars.md</code> — 内容支柱（主要写哪些方向）</li><li><code>topic-frameworks.md</code> — 选题框架（怎么想选题）</li></ul><h3 id="xhsops-specs-—-规则定义" tabindex="-1">.xhsops/specs/ — 规则定义 <a class="header-anchor" href="#xhsops-specs-—-规则定义" aria-label="Permalink to &quot;.xhsops/specs/ — 规则定义&quot;">​</a></h3><p>定义「什么算合格」：</p><table tabindex="0"><thead><tr><th>文件</th><th>作用</th></tr></thead><tbody><tr><td><code>note.spec.md</code></td><td>笔记结构规则</td></tr><tr><td><code>review.spec.md</code></td><td>审核标准</td></tr><tr><td><code>trend.spec.md</code></td><td>热点适切性判断</td></tr><tr><td><code>publish.spec.md</code></td><td>发布包要求</td></tr></tbody></table><h3 id="xhsops-commands-—-workflow-定义" tabindex="-1">.xhsops/commands/ — workflow 定义 <a class="header-anchor" href="#xhsops-commands-—-workflow-定义" aria-label="Permalink to &quot;.xhsops/commands/ — workflow 定义&quot;">​</a></h3><p>host-agnostic 的步骤文档，定义每个 workflow 的具体行为。</p><h3 id="xhsops-prompts-—-agent-协议" tabindex="-1">.xhsops/prompts/ — agent 协议 <a class="header-anchor" href="#xhsops-prompts-—-agent-协议" aria-label="Permalink to &quot;.xhsops/prompts/ — agent 协议&quot;">​</a></h3><p>agent 在各阶段的输出模板，确保产出格式一致。</p><h3 id="xhsops-quick-—-quick-runs" tabindex="-1">.xhsops/quick/ — quick runs <a class="header-anchor" href="#xhsops-quick-—-quick-runs" aria-label="Permalink to &quot;.xhsops/quick/ — quick runs&quot;">​</a></h3><p>每次 <code>quick</code> 命令创建的产物目录。</p><h3 id="xhsops-trends-—-trend-runs" tabindex="-1">.xhsops/trends/ — trend runs <a class="header-anchor" href="#xhsops-trends-—-trend-runs" aria-label="Permalink to &quot;.xhsops/trends/ — trend runs&quot;">​</a></h3><p>每次 <code>hot</code> 命令创建的产物目录。</p><h3 id="xhsops-campaigns-—-campaigns" tabindex="-1">.xhsops/campaigns/ — campaigns <a class="header-anchor" href="#xhsops-campaigns-—-campaigns" aria-label="Permalink to &quot;.xhsops/campaigns/ — campaigns&quot;">​</a></h3><p>每次 <code>plan</code> 命令创建的产物目录。</p><h3 id="xhsops-knowledge-—-复盘经验" tabindex="-1">.xhsops/knowledge/ — 复盘经验 <a class="header-anchor" href="#xhsops-knowledge-—-复盘经验" aria-label="Permalink to &quot;.xhsops/knowledge/ — 复盘经验&quot;">​</a></h3><table tabindex="0"><thead><tr><th>文件</th><th>作用</th></tr></thead><tbody><tr><td><code>winning-patterns.md</code></td><td>有效模式</td></tr><tr><td><code>failed-patterns.md</code></td><td>失败教训</td></tr><tr><td><code>trend-lessons.md</code></td><td>热点经验</td></tr></tbody></table><p>这些是 AI 创作时的参考库，每次 <code>archive</code> 会自动回流经验。</p><h3 id="publish-—-发布成品" tabindex="-1">publish/ — 发布成品 <a class="header-anchor" href="#publish-—-发布成品" aria-label="Permalink to &quot;publish/ — 发布成品&quot;">​</a></h3><p>最终给人看的发布制品，按日期组织。每个发布包含：</p><ul><li><code>note.md</code> — 终稿正文</li><li><code>cover-brief.md</code> — 封面设计要求</li><li><code>assets.md</code> — 配图素材</li><li><code>publish-guide.md</code> — 发布引导</li></ul>`,35)])])}const m=a(o,[["render",p]]);export{u as __pageData,m as default};
